use strict;
use warnings;
use PDF::API2;
use Text::CSV;

# Open the PDF file
my $pdf = PDF::API2->open('document.pdf');

# Create a CSV writer
my $csv = Text::CSV->new({ binary => 1 });

# Loop through each page in the PDF
for my $page (1 .. $pdf->pages) {
  my $text = $pdf->page($page)->text;

  # Extract specific information
  if ($text =~ /Date: (\d{1,2}\/\d{1,2}\/\d{4})/) {
    print "Date: $1\n";
  }
  if ($text =~ /Author: ([\w\s]+)/) {
    print "Author: $1\n";
  }

  # Handle tables (example for a simple CSV table extraction)
  my $table = $pdf->page($page)->copy_table;
  $csv->combine(@$table);
  print $csv->string, "\n";
}

# Clean up
$pdf->end;
